// Validate and enrich contact form data
const input = $input.first().json;
const body = input.body || input;

// Extract and validate fields
const name = (body.name || '').trim();
const email = (body.email || '').trim().toLowerCase();
const phone = (body.phone || '').trim();
const company = (body.company || body.organisation || '').trim();
const companySize = (body.company_size || body.companySize || '').trim();
const role = (body.role || body.title || '').trim();
const serviceInterest = (body.service_interest || body.serviceInterest || '').trim();
const message = (body.message || '').trim();

// UTM tracking
const utmSource = body.utm_source || body.utmSource || '';
const utmMedium = body.utm_medium || body.utmMedium || '';
const utmCampaign = body.utm_campaign || body.utmCampaign || '';
const utmContent = body.utm_content || body.utmContent || '';
const utmTerm = body.utm_term || body.utmTerm || '';

// Validation
if (!email || !email.includes('@')) {
  throw new Error('Valid email is required');
}
if (!name) {
  throw new Error('Name is required');
}

// Determine initial signals
const isDecisionMaker = /director|head|chief|vp|coo|chro|ceo|owner|founder|partner/i.test(role);
const isTargetIndustry = /insurance|financial|fintech|asset|fund|advisory|technology|software|saas|healthcare|pharmaceutical|manufacturing|mining|construction|retail|fmcg|telecom|agriculture|property|real estate|education|hospitality|consulting|engineering|legal|wealth management|accounting/i.test(company + ' ' + message);
const mentionsUrgency = /urgent|asap|immediately|soon|this quarter|next month|deadline/i.test(message);
const mentionsPain = /struggling|challenge|problem|issue|turnover|retention|engagement|burnout|toxic|dysfunction/i.test(message);
const isLargeCompany = /500|1000|enterprise|large|corporate/i.test(companySize);
const isMidMarket = /100|200|300|medium|mid/i.test(companySize);

return [{
  json: {
    name,
    email,
    phone,
    company,
    company_size: companySize,
    role,
    service_interest: serviceInterest,
    message,
    utm_source: utmSource,
    utm_medium: utmMedium,
    utm_campaign: utmCampaign,
    utm_content: utmContent,
    utm_term: utmTerm,
    signals: {
      is_decision_maker: isDecisionMaker,
      is_target_industry: isTargetIndustry,
      mentions_urgency: mentionsUrgency,
      mentions_pain: mentionsPain,
      is_large_company: isLargeCompany,
      is_mid_market: isMidMarket
    },
    received_at: new Date().toISOString()
  }
}];

