// Parse Ollama scoring response and merge with form data
const formData = $node['2. Validate & Enrich'].first().json;
const ollamaResponse = $input.first().json;

let scoring = {};
try {
  const responseText = ollamaResponse.response || ollamaResponse.message?.content || JSON.stringify(ollamaResponse);
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  scoring = JSON.parse(cleaned);
} catch (e) {
  const match = (ollamaResponse.response || '').match(/\{[\s\S]*\}/);
  if (match) {
    scoring = JSON.parse(match[0]);
  } else {
    scoring = {
      lead_score: 5,
      lead_temperature: 'WARM',
      buyer_persona: 'Unknown',
      urgency: 'medium',
      scoring_breakdown: {},
      next_action: 'nurture_sequence',
      ai_analysis: 'Could not parse scoring response. Defaulting to WARM.'
    };
  }
}

// Apply VIP threshold (15+, lowered from 20)
const leadScore = scoring.lead_score || 0;
let temperature = scoring.lead_temperature || 'COLD';
if (leadScore >= 15) temperature = 'HOT';
else if (leadScore >= 8) temperature = 'WARM';
else temperature = 'COLD';

return [{
  json: {
    ...formData,
    lead_score: leadScore,
    lead_temperature: temperature,
    buyer_persona: scoring.buyer_persona || 'Unknown',
    urgency: scoring.urgency || 'medium',
    scoring_breakdown: scoring.scoring_breakdown || {},
    next_action: scoring.next_action || 'nurture_sequence',
    ai_analysis: scoring.ai_analysis || '',
    is_vip: leadScore >= 15
  }
}];

